mapper.select:
select role, content, dialogue_id as dialogueId, creat_time as createTime
from deepseek_dialogue_info
where dialogue_id = #{dialogueId}

    and account = #{account}

order by creat_time asc

mapper.delete:
DELETE FROM deepseek_dialogue_info
WHERE dialogue_id = #{dialogueId}
AND account = #{account}

mapper.select:
SELECT COUNT(DISTINCT dialogue_id)
FROM deepseek_dialogue_info
WHERE account = #{account}
